import React, { useEffect, useState } from 'react';
import axios from 'axios';
import Slider from 'react-slick';
import "slick-carousel/slick/slick.css";
import "slick-carousel/slick/slick-theme.css";
import '../Styles/Global.css';

const Home = () => {
  const [featuredPlants, setFeaturedPlants] = useState([]);
  const [categories, setCategories] = useState([]);

  useEffect(() => {
    const fetchFeatured = async () => {
      try {
        const res = await axios.get('http://localhost:5000/api/admin/products/featured');
        setFeaturedPlants(res.data);
      } catch (error) {
        console.error('Failed to fetch featured plants', error);
      }
    };
    fetchFeatured();
  }, []);

  useEffect(() => {
    const fetchCategories = async () => {
      try {
        const res = await axios.get('http://localhost:5000/api/admin/products/categories');
        setCategories(res.data);
      } catch (error) {
        console.error('Failed to fetch categories', error);
      }
    };
    fetchCategories();
  }, []);

  const carouselSettings = {
    dots: true,
    infinite: true,
    speed: 1000,
    slidesToShow: 1,
    slidesToScroll: 1,
    autoplay: true,
    autoplaySpeed: 4000,
    arrows: false,
  };

  return (
    <div className="main-container">
      {/* HERO CAROUSEL */}
      <section className="hero-carousel">
        <Slider {...carouselSettings}>
          <div><img src="/assets/carousel1.jpg" alt="Greenhouse" className="carousel-image" /></div>
          <div><img src="/assets/carousel2.jpg" alt="Indoor Plants" className="carousel-image" /></div>
          <div><img src="/assets/carousel3.jpg" alt="Garden Tools" className="carousel-image" /></div>
        </Slider>
        <div className="hero-text-overlay">
          <h1>Welcome to NatureNest 🌿</h1>
          <p>Discover, shop, and learn plant care from the experts.</p>
          <a href="/catalog"><button>Shop Now</button></a>
        </div>
      </section>

      {/* CATEGORY SECTION */}
      <section className="category-section">
        <h2>Shop by Category</h2>
        <div className="category-cards">
          {Array.isArray(categories) &&
            categories.map((category, index) => {
              if (!category || typeof category.name !== 'string') return null;

              return (
                <a
                  key={index}
                  href={`/catalog?category=${category.name.toLowerCase()}`}
                  className="category-card"
                >
                  <img
                    src={`http://localhost:5000/Uploads/${category.imageUrl || 'placeholder.jpg'}`}
                    alt={category.name}
                  />
                  <h3>{category.name} Plants</h3>
                </a>
              );
            })}
        </div>
      </section>

      {/* FEATURED PRODUCTS */}
      <section className="featured-section">
        <h2>Featured Plants</h2>
        <div className="plant-grid">
          {Array.isArray(featuredPlants) &&
            featuredPlants.map((plant) => (
              <div className="plant-card" key={plant._id}>
                <img
                  src={`http://localhost:5000/uploads/${plant.imageUrl}`}
                  alt={plant.name}
                />
                <h3>{plant.name}</h3>
                <p>${plant.price}</p>
                <a href={`/product/${plant._id}`}>
                  <button>View Details</button>
                </a>
              </div>
            ))}
        </div>
      </section>

      {/* FOOTER */}
      <footer className="footer">
        <p>&copy; {new Date().getFullYear()} NatureNest | All rights reserved 🌱</p>
      </footer>
    </div>
  );
};

export default Home;
